input  wire clk,
input  wire data_in,
output  wire serial_out
);

          // 8-bit shift register
      // With a walking '1' pattern for visual verification

      reg [7:0] shift_reg = 8'b00000001;
      reg [23:0] slow_counter = 0;

      // Slow down the shift for visual verification
      // At 50MHz, shift every 2^24 / 50MHz ≈ 0.34 seconds
      always @(posedge clk) begin
          slow_counter <= slow_counter + 1'b1;
          if (slow_counter == 0) begin
              // Rotate left: bit 7 moves to bit 0
              shift_reg <= {shift_reg[6:0], shift_reg[7]};
          end
      end

      // For testing with data_in: use slow_counter overflow as "data"
      // In real use, connect data_in to shift_reg[0] input
      // For visual test, we use the rotating pattern

      // Active-low LED output
      assign serial_out = ~shift_reg[7];



endmodule
